var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"으음, 역시 총소리만으로는 불협화음이 너무 심하군요.","JPN":"うーん、やはり銃声だけだと不協和音になりますね。","ENG":"Mm, gunshots alone are too dissonant.","TWN":"嗯，光是槍聲就太不和諧了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그럼 선율을 조금 더 더해볼까요?","JPN":"旋律をもう少し足してみましょうか。","ENG":"Shall I add a little more melody?","TWN":"那麼，要再加入更多的旋律嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"으아……! 으아아……!! 내 몸이 녹아내리고 있어……!! 으아아!!","JPN":"うあ……！　うああ……！！　体が溶け落ちている……！！　うわあ！！","ENG":"Aaah...! AAAGH...!! My body's melting...!! AAAARGH!!","TWN":"我的天啊……！啊……！！我的身體正在融化……！！呃啊啊！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"진정해!! 이 총에 총구 들이밀지 마……!!","JPN":"落ち着け！！　銃に銃口を向けるな……！！","ENG":"Calm down! Stop pointing your gun around everywhere...!","TWN":"冷靜點！！別用那把槍指著我……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"열명의인디언이선에서있었다. 한명이집으로걸어가아홉이되었다. 아홉의인디언이문을잡아흔들다가, 한명이떨어져…….","JPN":"10人のインディアンの子が並んでいた。一人が帰って9人になった。9人のインディアンの子が扉を揺すり、一人が落っこちて……","ENG":"Tenlittleindiansstandinginaline. Onetoddledhomeandthentherewerenine. Ninelittleindiansswingingonagate. Onetumbledoffandthen...","TWN":"十個小士兵。一個走回家，十個只剩九。九個小士兵。抓門在搖晃，九個只剩八……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"비명과 통곡이 더해지니. 이제 좀 들을 만하군요.","JPN":"悲鳴と痛哭が加わったら、やっと少しは聞きごたえが出てきましたね。","ENG":"With the added screams and wailing, it is much better.","TWN":"尖叫聲和哀號聲越來越大。這個旋律值得一聽呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"이 자리에 저의 악단이 있었다면 좀 더 멋진 연주를 보여드릴 수 있었을 텐데요.","JPN":"ここに私の楽団がいてくれたら、もっと素敵な演奏をお聞かせすることができたのに、残念です。","ENG":"If only my Orchestra was here, we would have been able to put on a spectacular performance.","TWN":"如果我的樂團在這裡，一定能夠為你呈現出更好的演奏。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kuh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후우. 미안하지만, 필요 없거든……?","JPN":"ふう、悪いけど……遠慮するよ。","ENG":"Huu... Sorry, but I'll decline...","TWN":"呼。抱歉，但我不需要……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"정신 나갈 것 같은 소음이나 만들면서, 지휘자를 자청하다니 부끄럽지도 않아?","JPN":"気が狂いそうな騒音しか作り出せないくせに、指揮者を名乗るなんて恥ずかしくないの？","ENG":"Aren't you ashamed to call yourself a conductor when all you do is create noise?","TWN":"只會製造噪音的指揮家，你不覺得這樣很丟人嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"미의 기준이 시대마다 바뀌듯, 당신과 저의 관점이 그만큼 다르다고 할 수 있겠죠.","JPN":"あなたと私の観点が違うのでしょう。時代によって美の基準が変わるのと同じように、ですね。","ENG":"Just as the standard of beauty changes over time, it could be said that you and I merely have different perspectives.","TWN":"正如美麗的標準會隨著時間的推移而變化一樣，可以說你我的觀點並不相同。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"개개인이 받아들이는 예술은 상대적이니까요.","JPN":"一人一人の感じる芸術は主観的なものですから。","ENG":"For art is subjective to each individual.","TWN":"每個人接受的藝術都是相對的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"의외네? 그림자 주제에 인간 같은 소리를 하잖아?","JPN":"へえ、シャドウのくせに人間みたいなことを言うじゃない。","ENG":"That's surprising. A Shadow is actually making sense like a human being.","TWN":"奇怪？比起暗影你更像個人類。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"잡담을 꺼내시는 것 보니, 슬슬 비책이 다 떨어진 모양이로군요. 환상종의 후예.","JPN":"そんな無駄話を口にするとは……そろそろ秘策も切れたところでしょうか。","ENG":"Seeing how you are making small talk, it seems that you are running out of options, descendant of Bygones.","TWN":"從你閒聊的舉動來看，你似乎已經沒什麼手段了。夢幻品種的後裔。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 이거 들켰나 봐?","JPN":"ふふ、バレた？","ENG":"Fu fuu, you caught me.","TWN":"呵呵，看來被你發現了？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 전대원이 둘이나 죽었고, 아르콘 전대에서도 벌써 여럿이 당했어.","JPN":"うちの戦隊員が二人も死んじゃったし、アルコン戦隊も結構な数がやられてしまった。","ENG":"Two members from my division are already dead, and Arkon has already suffered a massive loss.","TWN":"我們戰隊已有兩名成員死亡，阿勒坤戰隊也失去了好幾名隊員。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 외 일반 보병 전력은…… 일일이 숫자를 헤아릴 수 없을 정도야.","JPN":"それ以外に一般歩兵の被害は……数えきれない。","ENG":"For the infantry... There are more than I can count.","TWN":"其餘的普通士兵……數量太多了已經無法統計。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"단원들의 서포트가 없는 마에스트로라면 격파가 가능할지도 모른다고 생각했는데…….","JPN":"楽団員のサポートがないマエストロなら撃破できると思ったけど、誤算だったようね……","ENG":"I thought it might be possible to defeat Maestra when she had no support from her members...","TWN":"還以為沒有了團員的協助，就可以擊敗指揮家……"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 괜히 데모고르곤이라고 부르는 게 아니었네.","JPN":"さすが、デモゴルゴンという名前は伊達じゃないというわけか。","ENG":"But I guess there's a reason she's called the Demogorgon.","TWN":"畢竟，她被稱為魔神也不是沒有道理的。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그럼, 이제 슬슬 막을 내리도록…… ","JPN":"では、そろそろ幕を下ろ…… ","ENG":"Now, it's time to bring it to a close...","TWN":"那麼，讓我們結束吧……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전 대원! 내 능력으로 마에스트로를 속박시켰다!","JPN":"全隊員！　私の能力でマエストロを束縛した！","ENG":"Everyone! I've bound Maestra with my powers!","TWN":"全體隊員！我用我的能力困住指揮家！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_ICE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이게 마지막 기회야……!! 모든 화력을 마에스트로에게 집중하도록……!!","JPN":"これが最後のチャンスだ……！！　すべての火力をマエストロに集中させる……！！","ENG":"This is our last chance...! Fire everything you've got on Maestra...!!","TWN":"這是最後的機會……！集中火力攻擊……！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_ICE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};